const hsl = (c, a) => a !== undefined ? `hsla(${c.h},${c.s}%,${c.l}%,${a})` : `hsl(${c.h},${c.s}%,${c.l}%)`;
const hslShift = (c, ls) => `hsl(${c.h},${c.s}%,${Math.max(0, Math.min(100, c.l + ls))}%)`;
